#include<bits/stdc++.h>
using namespace std;
int n,k;
vector<pair<int,int>> mp[200010];
int rt,tot,siz[200010],son[200010],min1[1000010],ans=INT_MAX,dis1[200010],dis2[200010],dl;
bool vis[200010];
void add(int u,int v,int w)
{
    mp[u].push_back(make_pair(v,w));
}
void getrt(int x,int fa=-1)
{
    siz[x]=1;
    son[x]=0;
    for(auto i:mp[x])
    {
        int v=i.first,val=i.second;
        if(v!=fa&&!vis[v])
        {
            getrt(v,x);
            siz[x]+=siz[v];
            son[x]=max(son[x],siz[v]);
        }
    }
    son[x]=max(son[x],tot-siz[x]);
    if(son[x]<son[rt])
    {
        rt=x;
    }
}
void getdis(int x,int fa,int d1,int d2)
{
    if(d1>k)
    {
        return;
    }
    dis1[++dl]=d1;
    dis2[dl]=d2;
    for(auto i:mp[x])
    {
        int v=i.first,val=i.second;
        if(v!=fa&&!vis[v])
        {
            getdis(v,x,d1+val,d2+1);
        }
    }
}
void getans(int x)
{
    min1[0]=0;
    dl=0;
    for(auto i:mp[x])
    {
        int v=i.first,val=i.second;
        if(!vis[v])
        {
            int pdl=dl;
            getdis(v,x,val,1);
            for(int j=pdl+1;j<=dl;j++)
            {
                ans=min(ans,min1[k-dis1[j]]+dis2[j]);
            }
            for(int j=pdl+1;j<=dl;j++)
            {
                min1[dis1[j]]=min(min1[dis1[j]],dis2[j]);
            }
        }
    }
    for(int i=1;i<=dl;i++)
    {
        min1[dis1[i]]=1e9;
    }
}
void solve(int x)
{
    vis[x]=true;
    getans(x);
    for(auto i:mp[x])
    {
        int v=i.first,val=i.second;
        if(!vis[v])
        {
            tot=siz[v];
            rt=0;
            getrt(v,x);
            solve(rt);
        }
    }
}
int main()
{
    scanf("%d%d",&n,&k);
    for(int i=1;i<n;i++)
    {
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        u++;
        v++;
        add(u,v,w);
        add(v,u,w);
    }
    tot=n;
    son[0]=n+1;
    getrt(1);
    memset(min1,0x3f,sizeof(min1));
    solve(rt);
    if(ans>=n)
    {
        ans=-1;
    }
    printf("%d",ans);
    return 0;
}
